define("mod_iearchy/directory",[],function(){var createPlaceholder=function(initials,className){var placeholder=document.createElement("div");placeholder.className=className;placeholder.textContent=initials&&initials.trim()?initials.trim():"?";return placeholder;},createImage=function(imageUrl,alt,fallbackInitials,className,placeholderClass){var image=document.createElement("img");image.className=className;image.src=imageUrl;image.alt=alt;image.loading="lazy";image.addEventListener("error",function(){var parent=image.parentNode;if(parent){parent.innerHTML="";parent.appendChild(createPlaceholder(fallbackInitials,placeholderClass));}});return image;},initRoot=function(root){var overlay=root.querySelector("#sdOverlay"),closeButton=root.querySelector("#sdClose"),modalImageWrap=root.querySelector("#sdModalImgWrap"),modalName=root.querySelector("#sdModalName"),modalPosition=root.querySelector("#sdModalPosition"),modalDescription=root.querySelector("#sdModalDesc"),lastFocused=null;if(!overlay||!closeButton||!modalImageWrap||!modalName||!modalPosition||!modalDescription){return;}var closeModal=function(){overlay.classList.remove("is-open");overlay.setAttribute("aria-hidden","true");document.body.style.overflow="";if(lastFocused){lastFocused.focus();lastFocused=null;}},openModal=function(card){var fullname=card.dataset.fullname||"",position=card.dataset.position||"",imageUrl=card.dataset.imageUrl||"",initials=card.dataset.initials||"?",hasImage=card.dataset.hasImage==="true"&&imageUrl.trim()!=="",descriptionNode=card.querySelector(".sd-card__desc"),description=descriptionNode?descriptionNode.textContent.trim():"";modalImageWrap.innerHTML="";if(hasImage){modalImageWrap.appendChild(createImage(imageUrl,fullname,initials,"sd-modal__img","sd-modal__img-placeholder"));}else{modalImageWrap.appendChild(createPlaceholder(initials,"sd-modal__img-placeholder"));}modalName.textContent=fullname;modalPosition.textContent=position;modalDescription.textContent=description||"—";lastFocused=card;overlay.classList.add("is-open");overlay.setAttribute("aria-hidden","false");document.body.style.overflow="hidden";closeButton.focus();};root.querySelectorAll(".sd-card").forEach(function(card){card.addEventListener("click",function(){openModal(card);});card.addEventListener("keydown",function(event){if(event.key==="Enter"||event.key===" "){event.preventDefault();openModal(card);}});});closeButton.addEventListener("click",closeModal);overlay.addEventListener("click",function(event){if(event.target===overlay){closeModal();}});document.addEventListener("keydown",function(event){if(event.key==="Escape"&&overlay.classList.contains("is-open")){closeModal();}});};return{init:function(){document.querySelectorAll('[data-region="mod-iearchy"]').forEach(initRoot);}};});
